// // This module decrements the count value on each positive edge of the clock signal and can be asynchronously reset.
module binary_counter_3bit(
    input clk,
    input reset,
    output reg [2:0] count
);

always @(posedge clk) begin
    if (reset) begin
        count <= 3'b000;
    end else begin
        count <= count + 1;
    end
end

endmodule
